#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    for (int tc = 0; tc < T; ++tc) {
        char word[105];
        if (!fgets(word, sizeof(word), stdin)) break;
        size_t len = strlen(word);
        if (len && word[len-1] == '\n') word[--len] = '\0';
        int end;
        scanf("%d", &end);
        getchar(); // consume newline after end
        printf("[");
        int printed = 0;
        for (int i = 0; i < end && i < (int)len; ++i) {
            if (printed) printf(", ");
            printf("'%c'", word[i]);
            printed = 1;
        }
        printf("]\n");
    }
    return 0;
}

