    for(int tc=0; tc<T; ++tc){
        string word;
        getline(cin, word);
        int end;
        cin>>end;
        getline(cin, dummy); // consume endline after end
        cout << "[";
        bool first = true;
        for(int i=0; i<end && i<(int)word.size(); ++i){
            if(!first) cout << ", ";
            cout << '\'' << word[i] << '\'';
            first = false;
        }
        cout << "]\n";
    }
    return 0;
}

code.Java:
import java.io.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            String word = br.readLine();
            if (word == null) word = "";
            int end = Integer.parseInt(br.readLine().trim());
            sb.append('[');
            boolean first = true;
            for (int i = 0; i < end && i < word.length(); ++i) {
                if (!first) sb.append(", ");
                sb.append('\'').append(word.charAt(i)).append('\'');
                first = false;
            }
            sb.append(']');
            if (tc != T-1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

