const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').split('\n');
let idx = 0;
const T = parseInt((input[idx++]||'').trim(), 10);
let outputs = [];
for (let tc = 0; tc < T; tc++) {
  const word = (input[idx++]||'');
  const end = parseInt((input[idx++]||'0').trim(), 10);
  let parts = [];
  for (let i = 0; i < end && i < word.length; i++) {
    parts.push(`'${word[i]}'`);
  }
  outputs.push('[' + parts.join(', ') + ']');
}
process.stdout.write(outputs.join('\n'));

